class Solution:
    def shortestAlternatingPaths(self, n: int, redEdges: List[List[int]], blueEdges: List[List[int]]) -> List[int]:
        graph = {i: [] for i in range(n)}
        for a, b in redEdges:
            graph[a].append((b, 'red'))
        for u, v in blueEdges:
            graph[u].append((v, 'blue'))
        queue = [(0, 0, 'red')]  
        visited = {0}
        answer = [float('inf')] * n
        answer[0] = 0
        while queue:
            node, distance, color = queue.pop(0)
            if node == n - 1:
                answer[node] = min(answer[node], distance)
            for neighbor, neighbor_color in graph[node]:
                if neighbor not in visited and (color == 'red' and neighbor_color == 'blue' or color == 'blue' and neighbor_color == 'red'):
                    visited.add(neighbor)
                    queue.append((neighbor, distance + 1, neighbor_color))
        return [x if x != float('inf') else -1 for x in answer]
